def find_longest_common_substring(strings):
    if len(strings) == 0:
        return ''
    elif len(strings) == 1:
        return strings[0]
    else:
        # sort the strings
        strings.sort(key=len)

        # take the first string as longest
        longest = strings[0]

        for s in strings:
            # check if the first string is a substring of the next string
            if longest in s:
                # if so, keep the longest
                longest = s
            else:
                # if not, find the longest substring 
                for i in range(len(longest)):
                    if longest[0:len(longest) - i] in s:
                        longest = longest[0:len(longest) - i]
                        break

        return longest

