def median(arr):
  arr.sort()
  if len(arr) % 2 != 0:
    median_index = int(len(arr) / 2)
    return arr[median_index]
  else:
    lower_index = int(len(arr) / 2) - 1
    upper_index = int(len(arr) / 2)
    return (arr[lower_index] + arr[upper_index]) / 2

