"""
Create a utility function to convert mathematical expressions to postfix notation in Python
"""

def to_postfix(expression):
    operations = {
        '+': 1, 
        '-': 1,
        '*': 2,
        '/': 2,
        '^': 3
    }
    output = []
    stack = []
    tokens = expression.split(' ')
    for token in tokens:
        if token in operations:
            while stack and operations[stack[-1]] >= operations[token]:
                output.append(stack.pop())
            stack.append(token)
        elif token == '(':
            stack.append(token)
        elif token == ')':
            while stack[-1] != '(':
                output.append(stack.pop())
            stack.pop()
        else:
            output.append(token)
    while stack:
        output.append(stack.pop())

    return output

