def caesar_cipher_encode(input_string, cipher):
    output = ''
    for c in input_string:
        ascii_val = ord(c)
        if (ascii_val > 64 and ascii_val < 91) or (ascii_val > 96 and ascii_val < 123):
            new_ascii_val = ascii_val + cipher
            if (ascii_val > 64 and ascii_val < 91 and new_ascii_val > 90) or (ascii_val > 96 and ascii_val < 123 and new_ascii_val > 122):
                new_ascii_val = ascii_val - 26 + cipher
            output += chr(new_ascii_val)
        else:
            output += c
    return output

class Fraction:

    def __init__(self, numerator, denominator):
        self.numerator = numerator
        self.denominator = denominator

    def __str__(self):
        return f"{self.numerator}/{self.denominator}"

    def __add__(self, other):
        denom = self.denominator * other.denominator
        num1 = self.numerator * other.denominator
        num2 = other.numerator * self.denominator
        numerator = num1 + num2
        return Fraction(numerator, denom)

    def __sub__(self, other):
        denom = self.denominator * other.denominator
        num1 = self.numerator * other.denominator
        num2 = other.numerator * self.denominator
        numerator = num1 - num2
        return Fraction(numerator, denom)

def is_prime(n): 
    # Corner cases 
    if (n <= 1): 
        return False
    if (n <= 3): 
        return True
    # This is checked so that we can skip  
    # middle five numbers in below loop 
    if (n % 2 == 0 or n % 3 == 0): 
        return False
    i = 5
    while(i * i <= n): 
        if (n % i == 0 or n % (i + 2) == 0): 
            return False
        i = i + 6
    return True

